mapper.select:
SELECT id, user_id, report_year, report_month,
       total_expense, prev_expense, diff_ratio,
       success_weeks, total_weeks, top_category, category_json,
       one_liner, mood, category_comment, advice,
       user_message, gulbi_reply, replied_at, generated_at
FROM monthly_report
WHERE user_id = #{userId}
  AND report_year = #{year}
  AND report_month = #{month}

mapper.update:
UPDATE monthly_report
SET user_message = #{userMessage},
    gulbi_reply  = #{gulbiReply},
    replied_at   = #{repliedAt}
WHERE id = #{id}
